code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Badge, Button, Card, icon } from 'decantr/components';

code.example:
function ServiceCatalogGrid({ services }) {
  const { div, span, h2, h3, p } = tags;
  const actionLabel = s => s === 'connected' ? 'Manage' : s === 'beta' ? 'Try Now' : 'Connect';
  const actionVariant = s => s === 'connected' ? 'outline' : s === 'beta' ? 'accent' : 'primary';
  const statusDot = s => s === 'connected' ? 'lp-dot lp-dot-success' : s === 'beta' ? 'lp-dot lp-dot-warning' : 'lp-dot';

  return div({ class: css('_flex _col _gap4') },
    div({ class: css('_flex _aic _jcsb') },
      h2({ class: css('_heading4') }, 'Services'),
      Badge({ variant: 'default' }, `${services.length} available`)
    ),
    div({ class: css('_grid _gcaf280 _gap4') },
      ...services.map(svc =>
        Card({ hover: true },
          Card.Body({ class: css('_flex _col _gap3 _p4') },
            div({ class: css('_flex _aic _gap3') },
              div({ class: css('_w10 _h10 _rfull _bgprimary/10 _flex _center') },
                icon(svc.icon, { size: '1.25em', class: css('_fgprimary') })
              ),
              div({ class: css('_flex _col _flex1') },
                div({ class: css('_flex _aic _gap2') },
                  h3({ class: css('_textsm _bold') }, svc.name),
                  div({ class: css(statusDot(svc.status)) })
                ),
                p({ class: css('_textxs _fgmuted') }, svc.description)
              )
            ),
            Button({ variant: actionVariant(svc.status), size: 'sm', class: css('_wfull') }, actionLabel(svc.status))
          )
        )
      )
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Badge, Button, Chip, icon } from 'decantr/components';

code.example:
function ServiceCatalogList({ services }) {
  const { div, span, h2 } = tags;
  const actionLabel = s => s === 'connected' ? 'Manage' : s === 'beta' ? 'Try Now' : 'Connect';

  return div({ class: css('_flex _col') },
    div({ class: css('_flex _aic _jcsb _px4 _py3 _borderB') },
      h2({ class: css('_heading5') }, 'Services'),
      Badge({ variant: 'default' }, `${services.length}`)
    ),
    ...services.map(svc =>
      div({ class: css('_flex _aic _gap3 _px4 _py3 _borderB') },
        div({ class: css('_w8 _h8 _rfull _bgprimary/10 _flex _center') },
          icon(svc.icon, { size: '1em', class: css('_fgprimary') })
        ),
        div({ class: css('_flex _col _flex1') },
          span({ class: css('_textsm _bold') }, svc.name),
          span({ class: css('_textxs _fgmuted') }, svc.description)
        ),
        Chip({ label: svc.status, size: 'xs', variant: svc.status === 'connected' ? 'success' : 'default' }),
        Button({ variant: 'ghost', size: 'sm' }, actionLabel(svc.status))
      )
    )
  );
}

